import React, { useState, useEffect, useCallback } from 'react';
import { schoolAPI } from '../services/api';
import api from '../services/api';
import toast from 'react-hot-toast';

const examAPI = {
  getAll:      ()    => api.get('/exams'),
  create:      (d)   => api.post('/exams', d),
  getSchedules:(id)  => api.get('/exams/schedules?examId=' + id),
  addSchedule: (d)   => api.post('/exams/schedules', d),
  saveMarks:   (d)   => api.post('/exams/marks', d),
  getResults:  (p)   => api.get('/exams/results', { params: p }),
};

const EXAM_TYPES = [
  { value:'unit_test',   label:'Unit Test'    },
  { value:'quarterly',   label:'Quarterly'    },
  { value:'half_yearly', label:'Half Yearly'  },
  { value:'annual',      label:'Annual'       },
  { value:'practical',   label:'Practical'    },
];

const TYPE_COLOR = {
  unit_test:   ['#DBEAFE','#1E40AF'],
  quarterly:   ['#EDE9F8','#5B21B6'],
  half_yearly: ['#FEF3C7','#92400E'],
  annual:      ['#D1FAE5','#065F46'],
  practical:   ['#FEE2E2','#991B1B'],
};

const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };

const MOCK_EXAMS = [
  { id:'e1', name:'Half Yearly Examination 2025', exam_type:'half_yearly', start_date:'2025-09-01', end_date:'2025-09-15', is_active:true },
  { id:'e2', name:'Unit Test 1 - June 2025',      exam_type:'unit_test',   start_date:'2025-06-10', end_date:'2025-06-12', is_active:true },
  { id:'e3', name:'Annual Examination 2024-25',   exam_type:'annual',      start_date:'2026-03-01', end_date:'2026-03-20', is_active:true },
];

export default function Examinations() {
  const [exams,     setExams]     = useState([]);
  const [classes,   setClasses]   = useState([]);
  const [loading,   setLoading]   = useState(true);
  const [isMock,    setIsMock]    = useState(false);
  const [showAdd,   setShowAdd]   = useState(false);
  const [saving,    setSaving]    = useState(false);
  const [selExam,   setSelExam]   = useState(null);
  const [activeTab, setActiveTab] = useState('schedule'); // schedule | marks | results
  const [schedules, setSchedules] = useState([]);
  const [form, setForm] = useState({ name:'', type:'unit_test', start:'', end:'' });

  const loadExams = useCallback(async () => {
    setLoading(true);
    try {
      const res = await examAPI.getAll();
      setExams(res.data.data || []); setIsMock(false);
    } catch {
      setExams(MOCK_EXAMS); setIsMock(true);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => {
    loadExams();
    schoolAPI.getClasses().then(r => setClasses(r.data.data||[])).catch(()=>{});
  }, [loadExams]);

  const handleAddExam = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await examAPI.create({ name:form.name, examType:form.type, startDate:form.start, endDate:form.end });
      toast.success('✅ Exam saved to database!');
      setShowAdd(false); setForm({ name:'', type:'unit_test', start:'', end:'' }); loadExams();
    } catch {
      const mock = { id:'m'+Date.now(), name:form.name, exam_type:form.type, start_date:form.start, end_date:form.end, is_active:true };
      setExams(p=>[mock,...p]); setIsMock(true);
      toast.success('Exam added (demo mode)'); setShowAdd(false);
    } finally { setSaving(false); }
  };

  const openExam = (exam) => { setSelExam(exam); setActiveTab('schedule'); setSchedules([]); };

  const stats = { total:exams.length, upcoming:exams.filter(e=>e.start_date>=new Date().toISOString().split('T')[0]).length, completed:exams.filter(e=>e.end_date<new Date().toISOString().split('T')[0]).length };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Examinations</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>
            {exams.length} exams configured &nbsp;
            {isMock ? <span style={{padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700}}>Demo mode</span>
                    : <span style={{padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700}}>🟢 Live DB</span>}
          </p>
        </div>
        <button onClick={()=>setShowAdd(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>+ New Exam</button>
      </div>

      {/* Stats */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:12,marginBottom:16}}>
        {[['Total Exams',stats.total,'#EDE9F8','#1E1B4B'],['Upcoming',stats.upcoming,'#DBEAFE','#1E40AF'],['Completed',stats.completed,'#D1FAE5','#065F46']].map(([l,v,bg,c])=>(
          <div key={l} style={{padding:'14px',background:bg,borderRadius:12,textAlign:'center'}}>
            <div style={{fontSize:24,fontWeight:800,color:c,lineHeight:1}}>{v}</div>
            <div style={{fontSize:11,color:c,marginTop:4,fontWeight:600}}>{l}</div>
          </div>
        ))}
      </div>

      {/* Exam list */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(320px,1fr))',gap:14}}>
        {loading && [1,2,3].map(i=><div key={i} style={{height:120,background:'#F9FAFB',borderRadius:12,border:'0.5px solid #E5E7EB'}}/>)}
        {!loading && exams.map(exam=>{
          const [bg,c] = TYPE_COLOR[exam.exam_type]||['#F3F4F6','#374151'];
          const typeCfg = EXAM_TYPES.find(t=>t.value===exam.exam_type);
          const today = new Date().toISOString().split('T')[0];
          const status = exam.end_date < today ? 'Completed' : exam.start_date <= today ? 'Ongoing' : 'Upcoming';
          const statusColor = { Completed:'#065F46', Ongoing:'#92400E', Upcoming:'#1E40AF' };
          const statusBg    = { Completed:'#D1FAE5', Ongoing:'#FEF3C7', Upcoming:'#DBEAFE' };
          return (
            <div key={exam.id} style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:18,cursor:'pointer',transition:'all .15s',position:'relative'}}
              onMouseEnter={e=>{e.currentTarget.style.boxShadow='0 4px 20px rgba(0,0,0,.1)';e.currentTarget.style.borderColor='#C4B5FD';}}
              onMouseLeave={e=>{e.currentTarget.style.boxShadow='';e.currentTarget.style.borderColor='#E5E7EB';}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:10}}>
                <span style={{padding:'3px 10px',borderRadius:20,fontSize:10,fontWeight:700,background:bg,color:c}}>{typeCfg?.label||exam.exam_type}</span>
                <span style={{padding:'3px 10px',borderRadius:20,fontSize:10,fontWeight:700,background:statusBg[status],color:statusColor[status]}}>{status}</span>
              </div>
              <div style={{fontSize:14,fontWeight:700,color:'#111827',marginBottom:8}}>{exam.name}</div>
              <div style={{fontSize:11,color:'#6B7280',display:'flex',gap:16}}>
                <span>📅 {exam.start_date||'—'}</span>
                <span>🏁 {exam.end_date||'—'}</span>
              </div>
              <div style={{marginTop:12,display:'flex',gap:8}}>
                <button onClick={()=>openExam(exam)} style={{flex:1,padding:'7px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:8,fontSize:12,fontWeight:700,cursor:'pointer'}}>📋 Schedule & Marks</button>
              </div>
            </div>
          );
        })}
        {!loading && exams.length===0 && (
          <div style={{gridColumn:'1/-1',padding:48,textAlign:'center',color:'#9CA3AF',background:'#fff',borderRadius:14,border:'0.5px solid #E5E7EB'}}>
            <div style={{fontSize:40,marginBottom:10}}>📝</div>
            <div style={{fontWeight:600,color:'#6B7280'}}>No exams yet</div>
            <div style={{fontSize:12,marginTop:4}}>Click "+ New Exam" to create your first examination</div>
          </div>
        )}
      </div>

      {/* Exam detail modal */}
      {selExam && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:400,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'#fff',borderRadius:18,width:680,maxHeight:'90vh',overflow:'auto',display:'flex',flexDirection:'column'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center',position:'sticky',top:0,background:'#fff',zIndex:1}}>
              <div>
                <div style={{fontWeight:700,fontSize:15}}>{selExam.name}</div>
                <div style={{fontSize:11,color:'#6B7280',marginTop:2}}>{selExam.start_date} → {selExam.end_date}</div>
              </div>
              <button onClick={()=>setSelExam(null)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>

            {/* Tabs */}
            <div style={{display:'flex',borderBottom:'1px solid #E5E7EB',padding:'0 20px'}}>
              {[['schedule','📅 Schedule'],['marks','✏️ Enter Marks'],['results','📊 Results']].map(([key,label])=>(
                <button key={key} onClick={()=>setActiveTab(key)}
                  style={{padding:'10px 16px',border:'none',borderBottom:activeTab===key?'2px solid #1E1B4B':'2px solid transparent',background:'transparent',color:activeTab===key?'#1E1B4B':'#6B7280',fontSize:13,fontWeight:activeTab===key?700:500,cursor:'pointer',marginBottom:-1}}>
                  {label}
                </button>
              ))}
            </div>

            <div style={{padding:20,flex:1}}>
              {activeTab==='schedule' && (
                <div>
                  <div style={{padding:'12px 16px',background:'#EDE9F8',borderRadius:10,marginBottom:14,fontSize:12,color:'#1E1B4B'}}>
                    📋 Schedule defines which subject is examined on which date for each class. Add exam dates and subjects below.
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr 1fr auto',gap:10,marginBottom:14,alignItems:'flex-end'}}>
                    {[['Date','date','examDate'],['Start Time','time','startTime'],['End Time','time','endTime'],['Max Marks','number','maxMarks']].map(([label,type,key])=>(
                      <div key={key}><label style={lbl}>{label}</label><input type={type} id={'sch_'+key} style={inp} defaultValue={key==='maxMarks'?'100':''}/></div>
                    ))}
                    <button onClick={async()=>{
                      const vals = {};
                      ['examDate','startTime','endTime','maxMarks'].forEach(k=>vals[k]=document.getElementById('sch_'+k)?.value);
                      const classSelect = document.getElementById('sch_classId');
                      const subjectInput = document.getElementById('sch_subject');
                      try {
                        await api.post('/exams/schedules', { examId:selExam.id, classId:classSelect?.value, subjectName:subjectInput?.value, ...vals });
                        toast.success('✅ Schedule saved to DB!');
                      } catch { toast.success('Schedule saved (demo)'); }
                    }} style={{padding:'10px 14px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:12,fontWeight:700,cursor:'pointer',height:42}}>+ Add</button>
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:16}}>
                    <div><label style={lbl}>Class</label>
                      <select id="sch_classId" style={inp}>
                        <option value="">Select Class</option>
                        {classes.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>
                    <div><label style={lbl}>Subject</label><input id="sch_subject" placeholder="e.g. Mathematics" style={inp}/></div>
                  </div>
                  <div style={{padding:'12px',background:'#F9FAFB',borderRadius:10,fontSize:12,color:'#6B7280',textAlign:'center'}}>
                    Saved schedules will appear here. Connect backend to view saved data.
                  </div>
                </div>
              )}
              {activeTab==='marks' && (
                <div>
                  <div style={{padding:'12px 16px',background:'#FEF3C7',borderRadius:10,marginBottom:14,fontSize:12,color:'#92400E'}}>
                    ✏️ Enter marks for each student. Select the class and subject first, then fill in marks and click Save.
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:14}}>
                    <div><label style={lbl}>Class</label>
                      <select style={inp}>
                        <option value="">Select Class</option>
                        {classes.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
                      </select>
                    </div>
                    <div><label style={lbl}>Subject</label><input placeholder="e.g. Mathematics" style={inp}/></div>
                  </div>
                  <div style={{padding:'24px',background:'#F9FAFB',borderRadius:10,textAlign:'center',color:'#6B7280'}}>
                    <div style={{fontSize:28,marginBottom:8}}>✏️</div>
                    <div style={{fontWeight:600}}>Select class and subject to load students</div>
                    <div style={{fontSize:12,marginTop:4}}>Students will load from the database for mark entry</div>
                  </div>
                </div>
              )}
              {activeTab==='results' && (
                <div>
                  <div style={{padding:'12px 16px',background:'#D1FAE5',borderRadius:10,marginBottom:14,fontSize:12,color:'#065F46'}}>
                    📊 Results show consolidated marks after entry. Data fetched from database.
                  </div>
                  <div style={{padding:'24px',background:'#F9FAFB',borderRadius:10,textAlign:'center',color:'#6B7280'}}>
                    <div style={{fontSize:28,marginBottom:8}}>📊</div>
                    <div style={{fontWeight:600}}>Results will appear after marks are entered</div>
                    <div style={{fontSize:12,marginTop:4}}>Enter marks in the "Enter Marks" tab first</div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Add Exam modal */}
      {showAdd && (
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:500,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:500}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>📝 New Examination</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAddExam} style={{padding:20}}>
              <div style={{marginBottom:12}}><label style={lbl}>Exam Name *</label><input required value={form.name} onChange={e=>setForm({...form,name:e.target.value})} placeholder="e.g. Half Yearly Examination 2025" style={inp} autoFocus/></div>
              <div style={{marginBottom:12}}><label style={lbl}>Exam Type *</label>
                <select value={form.type} onChange={e=>setForm({...form,type:e.target.value})} style={inp}>
                  {EXAM_TYPES.map(t=><option key={t.value} value={t.value}>{t.label}</option>)}
                </select>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:16}}>
                <div><label style={lbl}>Start Date *</label><input required type="date" value={form.start} onChange={e=>setForm({...form,start:e.target.value})} style={inp}/></div>
                <div><label style={lbl}>End Date *</label><input required type="date" value={form.end} onChange={e=>setForm({...form,end:e.target.value})} style={inp}/></div>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" disabled={saving} style={{padding:'10px 22px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>{saving?'⏳ Saving…':'💾 Save Exam'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
